select count(*) from postgres.comments as c, postgres.posts as p, postgres.postlinks as pl, postgres.posthistory as ph, postgres.votes as v, postgres.badges as b where p.id = c.postid and p.id = pl.relatedpostid and p.id = ph.postid and p.id = v.postid and b.userid = c.userid and c.score=0 and p.score<=32 and p.viewcount<=4146 and pl.linktypeid=1 and v.creationdate<=timestamp '2014-09-10 00:00:00';
